INSERT INTO channels VALUES(2,'UCeVhlE8_xSZBLIt29bzRpVg','Unshaken Faith Podcast','@UnshakenFaithPodcast','Unshaken Faith is a dynamic podcast where we explore real-life issues through the lens of unwavering faith in Jesus Christ. Join us for inspiring conversations, biblical teachings, and practical advice to help you stay grounded in your faith, no matter the challenges you face. Whether you''re navigating life''s storms or seeking deeper spiritual growth, this is your place for encouragement, hope, and the unshakable truth of God''s Word. Let’s walk this journey of faith together and build a life rooted in the unchanging promises of Christ.',34,'[]','https://www.youtube.com/channel/UCeVhlE8_xSZBLIt29bzRpVg');
INSERT INTO channels VALUES(3,'UCm_RMW_fQk-ELpPYUzor8lw','THE BEAT by Allen Parr','@thebeatagp','Biblical Encouragement And Truth (The B.E.A.T) is an online video ministry dedicated to communicating God''s word in a creative, practical and easy-to-watch format. These short 5-minutes-or-less videos seek to address questions most Christians have and to provide a forum for people to discuss various theological concepts and ideas. This channel also encourages people by challenging them to live out their true calling as a Christian. We release a new video EVERY TUESDAY. I hope you''ll enjoy these videos, share them and engage in the discussion!',1370000,'["how to study the bible","bible study","how to read the bible","bible study tips","allen parr the beat"]','https://www.youtube.com/channel/UCm_RMW_fQk-ELpPYUzor8lw');
INSERT INTO channels VALUES(5,'UCK9RJwC7Er16-Y8dvIQ-3tw','Apologia Studios','@ApologiaStudios',replace('Welcome to Apologia Studios! Our mission is to get the Gospel into all areas of culture. From theology to politics. We discuss everything from modern culture, to mormonism and the cults and do it all in a reformed and relevant way. \n\nSubscribe to this channel and visit https://www.apologiastudios.com to join our All-Access membership to get exclusive content like Collision, The Aftershow, Ask Me Anything w/ Jeff Durbin and our Academy classes on theological issues all for just a minimum donation of $9.95 a month!','\n',char(10)),595000,'["Jeff","Durbin","Apologetics","Christian","jehovah''s","witness","debate","Mormonism","Calvinism","LDS","Reformed","jeff durbin","jehovah''s witnesses","mormons"]','https://www.youtube.com/channel/UCK9RJwC7Er16-Y8dvIQ-3tw');
