INSERT INTO channels VALUES(11,'UC0A9YrHgD5hZ2JXQrxRPHsw','Daily Dose Of Wisdom','@Daily_Dose_Of_Wisdom',replace('Hello there! My name is Brandon McGuire & I started this channel to help equip believers for this challenging cultural moment so that we can reflect a more authentic, in-depth, and winsome portrait of who God is and what Christianity actually teaches.\n\nThere are a lot of objections to be addressed and questions to be answered. \n\nSkeptics and seekers are welcome. \nConversations are good. \nQuestions are good. \n\nNo Hate.\nJust Love.\n\nThe fear of the LORD is the beginning of wisdom. \n\nBusiness Inquiries:\ndailydoseofwisdom@lighthouseagents.com\n\n\n','\n',char(10)),1120000,'["Christianity","Apologetics"]','https://www.youtube.com/channel/UC0A9YrHgD5hZ2JXQrxRPHsw');
