INSERT INTO channels VALUES(19,'UCxsG-yjeM5dH_YOHpKqXDmg','Doreen Virtue','@Doreen_Virtue',replace('Doreen Virtue, Christian author. PLEASE NOTE: If you have questions for or about Doreen and her work, please send them as a direct message on Instagram.com/DoreenVirtue, instead of through this YouTube channel where messages are unmonitored.\n\nPlease visit: \n“How to Avoid New Age & New Thought Deception” read for FREE on Kindle Unlimited athttps://a.co/d/jjucK58\nInstagram.com/DoreenVirtue\nFacebook.com/DoreenVirtueForJesus\nTwitter.com/DoreenVirtue','\n',char(10)),376000,'["Jesus","Bible","new age to Jesus","Steven Bancarz","conversion","Fighting for the Faith","John MacArthur","grace to you","Ligonier ministries","Justin Peters","living waters ministries","NAR heresy","Ray comfort","American gospel movie","reformed theology","Alistair Begg","Paul Washer","new age deception","comparing new age to Christianity","ex new ager","new thought","ex new thoughter","Christian testimony","women''s Bible study","weekly devotional","Christian women"]','https://www.youtube.com/channel/UCxsG-yjeM5dH_YOHpKqXDmg');
INSERT INTO channels VALUES(20,'UCpln3ncy3rz6EL5IZjLFq7A','New Age to New Heart','@NewAgetoNewHeart',replace('Why did a professional psychic, a new age teacher, and an occultist practicing ritual magic renounce it all to follow Christ?\n\nWith first-hand understanding of deception, three ex-New Agers expose the hidden dangers of the New Age and equip Christians to stand firm against this present darkness and share the light of the Gospel.\n\nJoin Doreen Virtue, Jenn Nizza, and Jac Marino Chen on New Age to New Heart.\n','\n',char(10)),9600,'[]','https://www.youtube.com/channel/UCpln3ncy3rz6EL5IZjLFq7A');
INSERT INTO channels VALUES(21,'UCedYGs_lqq1uNet0u7qlSyQ','Cross Examined','@CrossExamined',replace('Welcome to the CrossExamined.org YouTube channel. We exist to cross-examine ideas against the truth of Christianity. Here you’ll find content from the Cross Examined team lead by our founder & president Dr. Frank Turek, the co-author of the best-selling Christian apologetics book, ‘I Don’t Have Enough Faith to be An Atheist’ (& several more). \n\nOur content includes Q&A clips from live college campus presentations around the country, debates with well-known atheists, interviews, podcast highlights, animation shorts, & the "I Don''t Have Enough Faith to be an Atheist" podcast.\n\nTopics we cover include addressing common misconceptions & objections made against the Bible, God, & Christianity. Demonstrating how historical, archaeological, scientific, & philosophical evidence all support the Christian worldview. We also discuss political & cultural movements that are incompatible with a Biblical worldview & how Christians can best navigate the cultural climate we find ourselves in today.\n\n','\n',char(10)),862000,'["Frank Turek","Christian","Apologetics","Worldview","Faith","Youth","God","Truth","Jesus","Bible","Cross Examined"]','https://www.youtube.com/channel/UCedYGs_lqq1uNet0u7qlSyQ');
INSERT INTO channels VALUES(22,'UCtWDnUokOD--s2aFxLT5uVA','Gavin Ortlund','@TruthUnites',replace('Truth Unites (https://truthunites.org) exists to promote gospel assurance through theological depth. \n\nGavin Ortlund (PhD, Fuller Theological Seminary) is President of Truth Unites, Visiting Professor of Historical Theology at Phoenix Seminary, and Theologian-in-Residence at Immanuel Nashville.\n\nTax Deductible Support: https://truthunites.org/donate/\nPatreon: https://www.patreon.com/truthunites\nPodcast: https://anchor.fm/truth-unites\n\nCheck out Gavin''s books and other writings at the link below.\n\n\n','\n',char(10)),182000,'["apologetics","theology","church","ecumenism","God","arguments for God","Christianity","truth","unity","doctrine","philosophy","Protestantism","Roman Catholicism","Eastern Orthodoxy","church history"]','https://www.youtube.com/channel/UCtWDnUokOD--s2aFxLT5uVA');
