INSERT INTO channels VALUES(28,'UC2S8HtvbfZjD73mosatFn1A','Jac Marino Chen','@JacMarinoChen',replace('Saved out of the occult, hermeticism, ritual magick, abuse, addiction, and a whole lot of depravity. ✝️\n♥️ Exalting Christ & exposing darkness\n➡️ No one comes to the Father except through Jesus. (John 14:6)\n\nJacMarino.com','\n',char(10)),18400,'["ex occult","ex hermeticism","ex ritual magick","Christian testimony","ex occultist","occult to Jesus testimony","alchemy","alien","alien abduction","Jesus Christ testimony","ex ceremonial magick","ex addict","ex addict testimony","ex astrologer","leaving the occult for Jesus","ex thoth","ex egyptian magic","ex hermeticist","ex hermetic","hermeticism to Jesus","hermeticism to Christianity","ex occult testimony","Jac Marino Chen","leaving the occult","ex new age","ex new ager","ex occultist"]','https://www.youtube.com/channel/UC2S8HtvbfZjD73mosatFn1A');
