INSERT INTO channels VALUES(37,'UC1xgSYQfbn1ubLK5dlqFfeQ','UnbelievableProject','@UnbelievableProject',replace('Wir sind UnbelievableProject c:\nWir sind ein freundliches, aktives und zur Zeit neues GMV Studio.\nEs wird hauptsächlich in unserem Studio um Fiesta Online Videos gehen.\nEs folgen :\n-einfache Videos\n-MEP''s\n-Vorstellungsvideos neuer Member & vieles mehr..\n\nStudiomember:\n\n-Suyaana [NaugthyListless] - Leader\nwww.youtube.com/user/Suyaana\n\n-TipsyTraceable [LunaticJudicious] - CoLeader\nwww.youtube.com/user/TipsyTraceable\n\n-AnjuuLein [Inconceivable]  - CoLeader\nwww.youtube.com/user/AnjuuLein\n\n-BrokenParticles [SpecialPunishment] - CoLeader\nwww.youtube.com/user/BrokenParticles\n\n-FiestaLuckyStar  [SilentButterfly] - Member\nwww.youtube.com/user/FiestaLuckyStar\n\n-Expiangi [PreciousIndependence]\n\n-UnawaresPedo  [BrokenCircle]\n\n-xDomoCookie [InfiniteReclusion]\n\n-Rikuna16  [LightningParadise]\n\n\nWir freuen uns über neue Bewerbungen und neue Member :)\n\n\n\nBesuche uns auf Ask :D  :\nhttp://ask.fm/UnbelievableProject','\n',char(10)),31,'[]','https://www.youtube.com/channel/UC1xgSYQfbn1ubLK5dlqFfeQ');
INSERT INTO channels VALUES(41,'UCv9-3aFss806GZFxNoTVduQ','Marcus Rogers','@MarcusRogers',replace('I''m just a nobody trying to tell everybody about somebody who can save anybody! Pastor of Firehouse Church in Chicago IL!\n\nInstagram: @MarcusRogersChildOfTheKing \n\nwww.marcusrogersministries.org for our monthly partners.Thank you and God bless!\n\nwww.firehoueschicago.org for those who want to join our weekly Bible studies. Just sign up for the free newsletter and you will get the link at the start of the week. No cost. 100 percent free. Just join the community of believers as we do Bible study and pray every day at 6 AM and 6 PM!\n','\n',char(10)),915000,'[]','https://www.youtube.com/channel/UCv9-3aFss806GZFxNoTVduQ');
INSERT INTO channels VALUES(43,'UCyKgD0DLtBN21gfThSalyUQ','Melissa Dougherty','@MelissaDougherty',replace('You''ll find a mixed bag of Jesus, theology, very okay satire, Christian apologetics, and cultural topics from a Christian perspective here on my channel. I''m an ex-New Thoughter (with a little Ex New Ager sprinkled in) and a lot of my videos focus on topics related to this as well. My hope is to help Christians thoughtfully know what they believe and why they believe it. \n\nI currently hold three degrees: \nB.A in Religious Studies \nA.A in Liberal Arts\nA.A in Early Childhood Multicultural Education. \n\nI am currently attending Southern Evangelical Seminary for my Master of Arts in Christian Apologetics. \n','\n',char(10)),406000,'["Melissa Dougherty","Apologetics","Christianity","Bible","Jesus","Ex New Ager","Ex New Age","New Age","theology","New Thought","Ex new thoughter"]','https://www.youtube.com/channel/UCyKgD0DLtBN21gfThSalyUQ');
