INSERT INTO channels VALUES(46,'UC31RZ-b3D1w452JLuzLVl4Q','The Remnant Radio','@TheRemnantRadio',replace('Welcome to The Remnant Radio, where we chase the “radical middle” between Word and Spirit. We believe in being deeply biblical and experiencing the Holy Spirit’s gifts today. If you’ve felt theologically homeless, hungry for both deep truth and God’s power, or lacked balanced voices, you’ve found your community. We were born from a desire for challenging conversations, theological depth, and experiencing all God has for us - in a way that remains biblically grounded.\n\nWe educate and equip believers, exploring theology, church history, and spiritual gifts in an engaging, relatable, and inspiring way. We bring together diverse Christian leaders, and while we don’t always agree (and don’t expect you to!), we humbly approach God’s Word together. Expect constructive, encouraging, entertaining, and inspiring dialogue. Our goal: help you break out of your theological echo chamber and engage in vibrant, balanced conversation rooted in truth and power.','\n',char(10)),197000,'["Theology Podcast","The Remnant Radio","Remnant Radio","Christian Theology","Christian Theology Podcast","Gifts Of The Spirit","trinitarian theology","Theology Interviews","Theology Conversations","Theology","Charismatic Theology","Pentecostal Theology","Continuationism","Theology Conversations"]','https://www.youtube.com/channel/UC31RZ-b3D1w452JLuzLVl4Q');
INSERT INTO channels VALUES(47,'UC7u2HaYBKDaLPcWmldxgGEA','Mike Winger','@MikeWinger',replace('You will learn to think biblically about everything so you can deal with false teaching, know what Scripture says about specific issues, prove Christianity is true, go deep into theology and become a go to resource for biblical knowledge so you can help others. I have a passion for helping others to carefully and thoughtfully understand and apply the Bible by creating the well-researched biblical content that you have been starving for ever since you first believed.\n I’m Mike Winger, after serving for 14 years as a pastor in the local church I have a heavy burden on my heart to get REAL Bible teaching and knowledge into the lives of others. I want to give you the teaching I’ve been craving for my whole Christian life. I want you to be able to hear me make the case for my views and to be able to reason it through for yourself.\n\nLive Q&A every Friday at 1pm Pacific time. \n\nYou can go beyond YT by following at the links below.\n','\n',char(10)),1010000,'["Mike Winger","biblethinker","apologetics","study","Christian worldview","Biblical worldview","theology","Bible explained","Bible studies","apologist","Christian","teacher","Bible"]','https://www.youtube.com/channel/UC7u2HaYBKDaLPcWmldxgGEA');
INSERT INTO channels VALUES(48,'UCadiEsTZ0hNxs5OxwGiyELQ','Testify','@TestifyApologetics',replace('I explain why you can trust the New Testament and believe Jesus'' resurrection. William Paley is my homeboy. \n\nJohn 19:35: "And he who has seen has testified, and his testimony is true; and he knows that he is telling the truth, so that you may believe."\n','\n',char(10)),228000,'["Christian apologetics","Christianity","apologetics","Miracles","Religion","Philosophy of Religion","Reliability of the Bible","Resurrection of Jesus","Bible","New Testament","Christian Testimony","Atheism","Christian","Bible","Historical Jesus","Religion and Spirituality","Apologetics","Faith","Jesus","Jesus Christ","deen","deenrespond","deen responds"]','https://www.youtube.com/channel/UCadiEsTZ0hNxs5OxwGiyELQ');
INSERT INTO channels VALUES(50,'UCmrVJGUS1u5-Hsm_BFS_1YA','Living Waters','@LivingWaters',replace('The vision of Living Waters is to inspire and equip Christians to fulfill the Great Commission. \n\nYou can learn more about our ministry at http://www.LivingWaters.com.\n\nYou can visit our store by going to LivingWaters.com/store, or by clicking the Living Waters Store link below.\n\nHosted by Ray Comfort, Emeal E.Z. Zwayne, Mark Spence, and Oscar Navarro.\n','\n',char(10)),1680000,'["evangelism","christianity","Ray Comfort","witnessing","Emeal Zwayne","Mark Spence"]','https://www.youtube.com/channel/UCmrVJGUS1u5-Hsm_BFS_1YA');
INSERT INTO channels VALUES(52,'UCj2yZE96gWsFyeVYnY9zXeg','Ruslan KD','@RuslanKD',replace('Ruslan KD, a Christian YouTuber of Armenian descent, was a refugee from Baku, Azerbaijan, before moving to the U.S. He started his YouTube channel in the mid-2010s, which has grown into a popular platform for discussions on faith, lifestyle, and music. Known for his insightful commentary on Christian living, culture, and personal development, Ruslan is also a speaker, author, and advocate for godly ambition. His mission is to encourage, empower, and inspire people to live a life that Blesses God. As Psalm 68:26 says, "Bless God in the great congregation," and Psalm 145:2 declares, "Every day will I bless Thee." Like Simeon, who "took Him up in his arms and blessed God" (Luke 2:28), Ruslan seeks to lead others in stewardship, relevant engagement, and practical living that honors the Lord.\n','\n',char(10)),849000,'["Ruslan","Ruslankd","Ruslan KD","Gods Dream","Chh","Kings Dream Ent","faith finance fitness","christian youtube","ruslan christian rapper","Christian youtuber","Follower of Jesus","politically agnostic","Bless God","Ruslan reacts","Ruslan rapper","Ruslan Christian Youtuber","faith and culture","Faith in Jesus"]','https://www.youtube.com/channel/UCj2yZE96gWsFyeVYnY9zXeg');
INSERT INTO channels VALUES(55,'UCC321oNTD2yrszfYoz3-X1w','Sean McDowell','@SeanMcDowell','Dr. Sean McDowell is a professor at Talbot School of Theology, Biola University. On this channel he tackles some of the biggest questions about God, morality, and contemporary culture. Visit www.seanmcdowell.org for more posts and info.',392000,'["apologetics","generation z","youth","students","truth","questions","Biola","worldview","author","relatioships","love","marriage","sex","Bible","evolution"]','https://www.youtube.com/channel/UCC321oNTD2yrszfYoz3-X1w');
INSERT INTO channels VALUES(57,'UC3g3LSHLqOm4HnsWi20uumg','Steven Bancarz','@StevenBancarz',replace('On this YouTube channel, we will be exposing the New Age movement while reinforcing the truth of the Gospel.  This channel will consist of refutations of New Age ideas and themes, while simultaneously establishing a rational case for the truth of Christianity.\n\nAs a former New Ager and former author of the Spirit Science website, I began a Christian after a spiritual experience of the presence of Jesus for the first time.  My eyes, since then, have been opened to the deception and lies propagated under the guise of "New Age spirituality" and the truth of the person of Jesus, the Son of God. I hope that the material on this channel is helpful to you, and that you are blessed and strengthened in your faith in Christ from the content of this channel.\n\n"Take no part in the unfruitful works of darkness, but instead expose them". - Ephesians 5:11\n\nWebsite: reasonsforjesus.com','\n',char(10)),192000,'["Steven Bancarz","Exposing the new age","reasons for jesus"]','https://www.youtube.com/channel/UC3g3LSHLqOm4HnsWi20uumg');
