INSERT INTO channels VALUES(59,'UCdlxWNzGGPKzQLMXkkyZkUQ','Wretched with Todd Friel','@WretchedNetwork',replace('Wretched TV and Radio are hosted by Todd Friel. On the show, you will see and hear live witnessing encounters, discussions of tough theological issues, and Christian commentary on current events. We might even make you laugh. Enjoy full episodes at https://fortisplus.org.\n','\n',char(10)),643000,'["wretched","wretchedtv","wretchedradio","media","christian","faith","god","jesus","holyspirit","church","evangelism","witnessing","openair","theology","gospel","religion","preaching","toddfriel","friel","wretch","apologetics","pneumatology","reformed","Christianity","discernment","fortis","fortisinstitute","bible","Christian worldview","Apologetics","Discipleship","Christian podcast","Christian TV","Bible study","Christian news","Marriage and family","Holiness","Truth","Christian living","Believers"]','https://www.youtube.com/channel/UCdlxWNzGGPKzQLMXkkyZkUQ');
