INSERT INTO channels VALUES(61,'UC1DuOQg0-nr99t17Ca8Hlag','Vlad Savchuk','@vladhungrygen',replace('Welcome to my channel! I’m the lead pastor of HungryGen Church, and my mission is to bring the full Gospel to the world. Here you’ll find bold, Bible-based teaching on deliverance, spiritual warfare, growing in intimacy with the Holy Spirit, overcoming sin, and living in freedom and dominion through Jesus Christ.\n\nYou can also follow my other channels:\n	•	Russian channel (teachings in Russian)\n	•	Spanish channel (teachings in Spanish)\n	•	Prayer channel (all prayers and instrumentals uploaded in one place)\n\n📖 Free Books & Resources — Vladimir Savchuk Ministries offers free books and tools to help you grow in faith.\n\n🔥 Join our Telegram Community to stay spiritually strong through:\n✅ Weekly Bible Memory\n✅ Mon–Fri Hour of Prayer\n✅ E-Courses, Books, & Devotionals\n','\n',char(10)),2400000,'["deliverance","holy spirit","deliverance ministry","isaiah saldivar","alexander pagani","bob larson","david diga hernandez","david hernandez","demon cast out","exorcism","casting out demons","spiritual warfare","fasting","vlad savchuk","vladimir savchuk","hungrygen","deliverance","holy spirit","deliverance ministry","isaiah saldivar","alexander pagani","bob larson","david diga hernandez","david hernandez","demon cast out","exorcism","casting out demons","spiritual warfare","fasting","vlad savchuk"]','https://www.youtube.com/channel/UC1DuOQg0-nr99t17Ca8Hlag');
INSERT INTO channels VALUES(62,'UCJX2EazMKUqBQV048px2aoA','Wes Huff','@WesHuff','Wesley Huff  (BA. MTS. PhD candidate) was born in Multan, Pakistan and spent a portion of his childhood in the Middle East. Wesley has participated in numerous talks and interfaith dialogue events at universities across North America and has been participating in public dialogues on issues of interfaith dialogue (particularly between Christianity and Islam), belief, and religion for just over a decade. Along with a number of other academic and informal associations, Wesley is currently the Central Canada Director at Apologetics Canada.',985000,'[]','https://www.youtube.com/channel/UCJX2EazMKUqBQV048px2aoA');
INSERT INTO channels VALUES(63,'UCdxnoWgNWJLEipq4pdhm9DA','Apologetics Canada','@ApologeticsCanada','Apologetics Canada''s mission is to equip the Christian community with a biblically sound, intellectually robust, and culturally engaged faith.',192000,'["Apologetics","Canada","gospel","Christianity","Jesus","God","Holy Spirit","Bible","Thinking Series","The Human Project","Reclaimed","humanization","dehumanization","human","religion","spirituality","New Testament","Old Testament"]','https://www.youtube.com/channel/UCdxnoWgNWJLEipq4pdhm9DA');
INSERT INTO channels VALUES(67,'UCicvc24eAbFp-thRrBnSP2A','Answers in Genesis','@answersingenesis',replace('Subscribe now to learn how to defend the Christian faith. \n\nAnswers in Genesis is an apologetics (Christianity-defending) ministry dedicated to enabling Christians to defend their faith and proclaim the good news of Jesus Christ effectively.\n\nOn our YouTube channel, you’ll find answers to your most pressing questions about key issues like creation, evolution, science, the age of the earth, and social issues. We desire to train believers to develop a worldview based on the Bible and expose the bankruptcy of evolutionary ideas and their implications. \n\nYou’ll hear from top teachers such as Ken Ham, Bryan Osborne, Dr. Georgia Purdom, Dr. Nathaniel Jeanson, Dr. Tim Chaffey, Dr. Terry Mortenson, and more.\n','\n',char(10)),900000,'[]','https://www.youtube.com/channel/UCicvc24eAbFp-thRrBnSP2A');
INSERT INTO channels VALUES(68,'UCQsYAEW0n3tGsRfMVfIRzRw','AoC Network','@aocnetwork',replace('We produce documentaries to strengthen your walk in Christ! See our “Exploring The Bible" series. \n\nThose who work with AoC Network are from various Christian traditions. We aim to create content that is biblical, educational, and can be valued by all followers of Christ. We are committed to Biblical teaching through cinematic video and online materials.\n\nNevertheless, we encourage our audience to also fellowship with their local Church community and to view our materials as an educational supplement in one’s walk with Christ. Many of our videos feature some of the greatest biblical movies produced on film. For those interested in acquiring the movies featured in our episodes, a Google search using the title and date provided in the ending credits will help with purchasing them.\n\nLearn more at: www.aocnetwork.org/about-us','\n',char(10)),1190000,'[]','https://www.youtube.com/channel/UCQsYAEW0n3tGsRfMVfIRzRw');
INSERT INTO channels VALUES(72,'UCVfwlh9XpX2Y_tQfjeln9QA','BibleProject','@bibleproject',replace('BibleProject creates free resources to help you experience the Bible. Everything we make is funded by generous supporters around the world. You can see our entire library of videos, podcasts, classes, check out our other resources, and give at bibleproject.com.\n\nYou can find us elsewhere:\n\nDownload our app: https://bibleproject.com/app/\nBibleProject Podcast on YouTube: https://www.youtube.com/@BibleProjectPodcast\nTikTok: https://www.tiktok.com/@bibleproject\nInstagram: https://www.instagram.com/thebibleproject\nFacebook: https://www.facebook.com/jointhebibleproject/\nX: https://twitter.com/bibleproject\n\n\nDo you speak another language? Check out our videos and reading plans in over 50 other languages at bibleproject.com/languages\n\n','\n',char(10)),5400000,'["Bible","Scripture","Christianity","Jesus","God","Bible Videos","bible","Project","bibleproject","Tim Mackie","Jon Collins"]','https://www.youtube.com/channel/UCVfwlh9XpX2Y_tQfjeln9QA');
INSERT INTO channels VALUES(81,'UCKr-liguaGWMf3f94eQXsug','Give Me An Answer with Stuart & Cliffe Knechtle','@givemeananswer',replace('The "Give Me An Answer" ministry began as an outgrowth of the dialogues \nCliffe Knechtle has had with students on various university campuses \nthroughout the United States. Stuart joined his dad Cliffe in 2015 and \nthey''ve teamed up to do this together. These universities include Tennessee \nMaine, Harvard, MIT, Florida, University of Texas, Texas State, Arizona, \nPrinceton, Michigan State, UCLA, UC Davis, Berkeley, Stanford, Oregon State, \nand UMass. Amherst.  \nCliffe spoke on these campuses in front of the Student Union or Library at \nnoon for five to ten minutes. At the close of his initial remarks, he''d open up \nthe time for questions and answers, which usually turned into a two to four \nhour dialogue with students. \nHis crowd size ranged from 25 - 500 students at a time, and between classes, \nnew students would join the discussion. This is an extremely effective way to \nreach a large number of university students with the Gospel of Christ.\n','\n',char(10)),960000,'["was jesus a real person","was jesus real","cliffe knechtle","give me an answer","stuart knechtle","askcliffe","cliffe knechtle debate","did jesus exist","proof jesus lived","jesus christ","historical evidence for jesus","christianity","bible","god","candace owens","RIP","give me an answer","askcliffe","cliffe knechtle debate","did jesus exist","proof jesus is real","proof jesus lived","jesus christ","historicity of jesus","bible","god","charlie kirk","proof jesus christ was real","ck19a","kac9","91sck","sc19k","k91cs"]','https://www.youtube.com/channel/UCKr-liguaGWMf3f94eQXsug');
INSERT INTO channels VALUES(82,'UCE1PSKHiQIi4WF9ZTHGJCRg','Good Fight Ministries','@goodfightministries',replace('Welcome to the official YouTube channel for Fight the Good Fight Ministries.\n\nWe are a non-profit ministry that exists for the glory of God, equipping Christians with Truth, exposing the unfruitful works of darkness (Ephesians 5:11), while maintaining a heart to win souls with the Gospel of Jesus Christ. Good Fight Ministries specializes in apologetics, discernment, bible prophecy, end times, and exposing the enemy’s tactics used in pop culture and the entertainment industry which lead people away from the biblical God of the bible. We carefully research growing religious trends and ideas that attempt to undermine biblical Christianity, covering various trends in present pop culture. The tools that Good Fight make available have proven to be incredibly effective in leading thousands of people to Christ and encouraging Believers in their walk with the Lord. Fight the Good Fight Ministries is a 501(c)(3) non-profit, tax exempt organization.','\n',char(10)),297000,'["Good Fight","Good Fight Ministries","Fight the Good Fight","Joe Schimmel","Christianity","Jesus Christ","Apologetics","Discernment","Bible","Hollywood''s War on God","Planned Parenthood","The Submerging Church","GoodFight","Marvel & DC''s War on God","God","Pop Culture"]','https://www.youtube.com/channel/UCE1PSKHiQIi4WF9ZTHGJCRg');
INSERT INTO channels VALUES(86,'UC8iU3x5kC8zhSJDmMW_maPQ','Little Light Studios','@littlelightstudios',replace('We challenge pop culture and inspire people to see beyond the screen through media that illuminates truth.\n','\n',char(10)),256000,'[]','https://www.youtube.com/channel/UC8iU3x5kC8zhSJDmMW_maPQ');
INSERT INTO channels VALUES(92,'UC8p6aqja2so3hfQCwaiutow','Off The Kirb Ministries','@offthekirb',replace('Off The Kirb Ministries shares Christian motivational videos, street preaching content, encouragement in God''s grace and more to help you grow as a believer through the power of Holy Spirit as you serve Jesus. If you''re a Christian, street preacher or follower of Jesus who needs encouragement in your faith; these videos will hopefully be a blessing in your Christian lifestyle. So please consider subscribing! \n\nI work full-time as an Evangelist based in Lancashire, England. My evangelistic outreach consists of open air preaching, church outreach events, pulpit preaching, youth ministry and of Christian YouTube videos! \nTo stay updated with my street preaching and other UK street preacher friends, check out our “Street Preaching Channel”\n\n*** I upload a NEW video every SATURDAY 9:30am Eastern Time. ***\n\nMuch love to you all in Christ,\n\nJoe Kirby','\n',char(10)),2740000,'[]','https://www.youtube.com/channel/UC8p6aqja2so3hfQCwaiutow');
INSERT INTO channels VALUES(94,'UClh4JeqYB1QN6f1h_bzmEng','Matt Fradd','@pintswithaquinas',replace('Long form discussions about the Catholic faith.\n\n🍺 Get episodes a week early,  and 🍺 enjoy exclusive streams with me! Become a Daily Wire Member and watch all of our content ad-free: https://www.dailywire.com/subscribe\n\n\n\n\n','\n',char(10)),844000,'[]','https://www.youtube.com/channel/UClh4JeqYB1QN6f1h_bzmEng');
