INSERT INTO channels VALUES(106,'UCh3wFR4mJvg9qKgrw3Wxueg','Think Biblically ','@thinkbiblically',replace('Asher Wilson (ThM), lecturer of Biblical Studies at ZBS and SIBS, has created this channel to help  Christians in Pakistan and across the globe to have a Biblical Worldview and live accordingly for the glory of our Savior God\n','\n',char(10)),20500,'["Religion","Pakistani Christian","Christian Music","Hindi Christian Music","Bible Teachings Urdu","Asher Wilson","Church of Messiah","Madam Asiya Nasir","Bible Teaching Hindi","Christians in Pakistan","Jamil Nasir","Qom ki Beti","Urud Christian Music","Arif Bhatti","Sherry Khan","Prof. Asher Wilson","Siloam Bible School","Christian Muslim","Seeker","Islam","Hinduism","Isaac TV","Anwar Fazal","Praise TV","Muslim Women"]','https://www.youtube.com/channel/UCh3wFR4mJvg9qKgrw3Wxueg');
INSERT INTO channels VALUES(111,'UC1okSIA8UEY8OqvtjGHFvzA','Whaddo You Meme??','@whaddoyoumeme',replace('Creating content that''s thoughtful, researched, respectful, and gospel centric. We''re here to help you understand how Christianity makes sense of life by breaking down culture''s leading voices and events, with the intent to help you grow spiritually, grow in your understanding of others, and grow in your understanding of the Gospel’s meaning for your life.\n\nCheck out one of our playlists on our home page to get started! \n\nBusiness inquires: Please contact us at contact@whaddoyoumeme.com\n\nBrand Deal inquires: wym@sailingmgmt.biz\n\nIf you would like to support this channel to help us put out more regular content, visit us on Patreon: https://www.patreon.com/whaddoyoumeme','\n',char(10)),571000,'["Christian apologetics","apologetics","christianity","jon McCray","what do you meme","urban apologetics","Jesus","bible","god","christ","theology","philosophy","David Wood","free","grace"]','https://www.youtube.com/channel/UC1okSIA8UEY8OqvtjGHFvzA');
INSERT INTO channels VALUES(115,'UCnrFlpro0xfYjz6s5Xa8WWw','Desiring God','@desiringGod',replace('Most people in the world have no experience of lasting joy in their lives. We’re on a mission to change that. All of our resources exist to guide you toward everlasting joy in Jesus Christ. \n\nLearn more at https://desiringGod.org.\n','\n',char(10)),1120000,'["John Piper","Desiring God","Christian Hedonism","Jesus","Christ","God","Christian Media"]','https://www.youtube.com/channel/UCnrFlpro0xfYjz6s5Xa8WWw');
INSERT INTO channels VALUES(117,'UCsJezu3tK45jPs0ywrq0S0Q','The Veritas Forum','@VeritasForum',replace('Founded in 1992, The Veritas Forum invites students and faculty to bring their whole selves to wrestle with life’s most confounding ideas and be changed by them.\n\nMotivated by the historic Christian faith that seeks to love God and neighbor, we offer robust programs and events that encourage students and faculty from universities across the globe to engage their backgrounds, beliefs, and passions in a diverse community of exploration—one that puts the Christian faith in dialogue with other beliefs and invites participants from all backgrounds to seek truth together. Because we believe that an openness to discovery—and a posture of humility—are foundational to both the Christian story and a flourishing university.\n\nLearn more at http://www.veritas.org\n','\n',char(10)),239000,'["veritas forum","apologetics","Christianity","discussion","faith","religion","university","generous dialogue","intellectual humility"]','https://www.youtube.com/channel/UCsJezu3tK45jPs0ywrq0S0Q');
INSERT INTO channels VALUES(119,'UCwEL6nUCZv_8b_ZRaubagFQ','Cultish','@TheCultishShow','Enter the Kingdom of the Cults with Cultish; a program that explores the impact of the cults from a theological, sociological, and psychological perspective. Immerse yourself in the thinking, teaching, strategies, and consequences born out of the nefarious leaders of these movements.',18600,'["cultish","cultish podcast","the cultish show","apologia studios","apologia","christian cult podcast","christian cult conversation","christian cult discussion","christian cult clips","cultish clips","cult clips"]','https://www.youtube.com/channel/UCwEL6nUCZv_8b_ZRaubagFQ');
INSERT INTO channels VALUES(128,'UCB5fF2L7GMyhOUMOtk6dhuA','Dr. John Lennox','@DrJohnLennox','John Lennox, Professor of Mathematics at Oxford University, is an internationally renowned speaker on the interface of science, philosophy and religion.',975,'[]','https://www.youtube.com/channel/UCB5fF2L7GMyhOUMOtk6dhuA');
INSERT INTO channels VALUES(129,'UCTnjq81SPmn90abHS6yi5Vg','Acts17Apologetics David Wood','@acts17apologeticsdavidwood77',replace('Adding videos of David Wood every other day. All updates of David Wood.\nActs 17 Apologetics is a Christian YouTube channel founded by Dr. David Wood (a former atheist) and Dr. Nabeel Qureshi (a former Muslim). Nabeel wrote the bestsellers “Seeking Allah, Finding Jesus” and “No God but One.” Then he went on to be with the Lord. David continues producing videos, dealing primarily with Christian apologetics (defending the existence of God, the Trinity, and the death, resurrection, and deity of Jesus Christ), Islam (analyzing Muhammad, the Quran, sharia, and jihad), atheism, and philosophy. David works regularly with fellow YouTubers Vocab Malone, Jon McCray (Whaddo You Meme??), the Apostate Prophet (an ex-Muslim), Anthony Rogers, and Sam Shamoun (Shamounian). The Acts17Apologetics channel features Christian testimonies and responses to popular atheists and Muslim apologists (e.g. Zakir Naik, Shabir Ally, Yusuf Estes, Mohammed Hijab, and Ali Dawah). https://www.minds.com/Acts17Apologetics','\n',char(10)),341,'[]','https://www.youtube.com/channel/UCTnjq81SPmn90abHS6yi5Vg');
INSERT INTO channels VALUES(131,'UCfO5jI4DPGScH5LH8KKa4Fg','Crossway','@CrosswayBooks',replace('Crossway is a not-for-profit ministry publishing gospel-centered, Bible-based content to honor Christ and serve the church. Our videos aim to help you understand the truth of God’s Word and its impact on all of life—for God’s glory.\n\nExplore interviews, devotionals, and resources for Bible study and discipleship. Subscribe for thoughtful content to strengthen your faith and deepen your study in God’s Word.\n','\n',char(10)),63800,'["Christian","Books","Publisher","Bible","ESV","study","religion","Christianity","Piper","Lecrae","Packer"]','https://www.youtube.com/channel/UCfO5jI4DPGScH5LH8KKa4Fg');
INSERT INTO channels VALUES(133,'UCl9StMQ79LtEvlrskzjoYbQ','Closer To Truth','@CloserToTruthTV',replace('Closer To Truth is the definitive source for Cosmos, Life, Mind, and Meaning. Filmed both on location and virtually, Closer To Truth features leading philosophers and scientists exploring humanity’s deepest questions.\n\nOn the air continuously since 2000, Closer To Truth is broadcast weekly on PBS and public television stations in the U.S. \n\nRobert Lawrence Kuhn is the creator, executive producer, writer and presenter of the series. Peter Getzels is the co-creator and producer/director. \n\nVisit our website for our entire library of over 5,000 in-depth video interviews: www.closertotruth.com\n\nCloser To Truth is a nonprofit endeavor made possible by funding from the Kuhn Foundation and other partners. All revenue generated from advertisements on our YouTube channel goes back into production so that we can continue to make our material free to everyone.\n','\n',char(10)),670000,'["consciousness","cosmos","meaning","cosmology","philosophy","atheism","skepticism","science","physics","education","theology","religion","closer to truth","Robert Lawrence Kuhn","philosophy of cosmology","philosophy of mind","scientist","PBS","sabine hossenfelder","neuroscience","mathematics","biology","mind","genetics","psychology","evolution","artificial intelligence","AI","physics","sci hub","astronomy","quantum physics","Quantum Mechanics","Ethics","aliens","outer space"]','https://www.youtube.com/channel/UCl9StMQ79LtEvlrskzjoYbQ');
