INSERT INTO channels VALUES(136,'UCRMlEcam-zu-maOA718QsFQ','More Pints With Aquinas','@morepintswithaquinas',replace('This channel is where we showcase the best clips from Pints With Aquinas, hosted by Matt Fradd. This show is an invitation to explore timeless truths and contemporary issues through the lens of faith and reason. Through engaging conversations with theologians, philosophers, apologists, and cultural commentators, we delve into ancient wisdom and profound insights that help us to know and live the Catholic faith. Whether you''re seeking intellectual growth, spiritual enrichment, or simply looking for a new perspective, Pints With Aquinas offers thoughtful discussions to challenge and inspire. ICXC + NIKA\n','\n',char(10)),51600,'[]','https://www.youtube.com/channel/UCRMlEcam-zu-maOA718QsFQ');
INSERT INTO channels VALUES(137,'UCVFe7xhG6rl0ruoMQCJDtnw','Cold-Case Christianity - J. Warner & Jimmy Wallace','@ColdCaseChristianity','This is the YouTube Channel of J. Warner and Jimmy Wallace. J. Warner is a Dateline featured Cold-Case Detective, Senior Fellow at the Colson Center for Christian Worldview, Adj. Professor of Christian Apologetics at Talbot School of Theology, Biola University,  and Author of Cold-Case Christianity, God’s Crime Scene, and Forensic Faith, and creator of the Case Makers Academy for kids.',174000,'["Apologetics","Christianity","Christian Worldview","Evidence","Jim Wallace","pleaseconvinceme","theology","J Warner Wallace","Christian Apologist","Questions about Jesus","Questions about Faith","Questions about God","Questions about Christianity"]','https://www.youtube.com/channel/UCVFe7xhG6rl0ruoMQCJDtnw');
INSERT INTO channels VALUES(138,'UCjxmO4cRpsL_g9pwR4sES4A','Laura Maxwell: Ex New Age Spiritualist','@LauraMaxwellExSpiritist',replace('Ex ''Alien/Spirit Guide and Ghost'' Channeller. Christian author. Ex NAR, New Apostolic Reformation: fa|se prophets'' 7 Mtn Mandate Dominion. \n\nAnti T.rump & M@GA Christian Nationa|ism. I left NAR 10 years before he became Pres!dent. I expose Ant*christ agenda, from Bible & inside knowledge of Luc|ferian Theosophy, when a New Age Spiritualist, 1980s-90s. \n\nThey taught Luc:fer is god over Aquarian Golden Age: Aliens and a man saviour-figure to bring Awakening - linking apostate NAR church/MAGA cult-doctrines, Bible predicts for these Endtimes.\n\nHonored to be a Christian tv/radio guest, from 2009. On Eternal Radio, I interviewed ex occultists: conversion stories and outreach to New Age, cults, occult & Ufology. I share via TV, radio, books/magazines & online.\n\nJesus still sets precious people free - deliverance from evil spirits. Articles by myself & others, see my blog OurSpiritualQuest.com\n\nFor the love of souls. Glory to God. Laura Maxwell, Scotland, UK.\n','\n',char(10)),5280,'["Spiritualist","Spiritualism","Medium","Occult","Seance","Spirits","Guides","Channelling","Ghost","Alien","Psychic","Clairvoyance","Aquarius","Meditation","Yoga","Reiki","Supernatural","Paranormal","Deliverance","Jesus","Prophecy","Ghost Hunting","Laura Maxwell","Luciferian","NWO","Antichrist","Great Tribulation","spiritguides","endtimes","antichristsystem","Revelation","truther","Golden Age","Lastdays","Tribulation","Armageddon","CE4","AFTERLIFE","healing","prophecy","cults","survivor","recovery","energyhealing","UFO","UAP","newagetojesus","witchcrafttochrist","crattochrist","exwitch"]','https://www.youtube.com/channel/UCjxmO4cRpsL_g9pwR4sES4A');
